import React, { useEffect, useState } from "react";
import axios from "axios";
import { useAuth } from "../context/AuthContext";

const LABELS = {
  nome: "Nome",
  ra: "RA",
  usuario: "Usuário",
  periodo_id: "Período ID",
  periodo_nome: "Período",
  periodo_turno: "Turno",
  pin: "PIN",
  role: "Tipo",
  cpf: "CPF",
  rg: "RG",
  numero_prontuario: "Prontuário",
  numero_gaveta: "Gaveta",
  cidade: "Cidade",
  endereco: "Endereço",
  numero: "Número",
  idade: "Idade",
  data_nascimento: "Nascimento",
  observacao: "Observação"
};

function renderDetalhes(log) {
  if (!log.detalhes || log.detalhes === "{}") return <span>-</span>;
  let data;
  try {
    if (typeof log.detalhes === "object") {
      data = log.detalhes;
    } else {
      data = JSON.parse(log.detalhes);
    }
  } catch {
    return <span>{String(log.detalhes)}</span>;
  }
  if (!data || typeof data !== "object") return <span>-</span>;
  const entries = Object.entries(data).filter(([k, v]) => v !== null && v !== undefined && v !== "");
  if (entries.length === 0) return <span>-</span>;
  return (
    <span>
      {entries.map(([k, v]) => `${LABELS[k] || k}: ${v}`).join(" | ")}
    </span>
  );
}

export default function TelaLogs() {
  const { user } = useAuth();
  const [logs, setLogs] = useState([]);
  const [filtros, setFiltros] = useState({
    usuario: "",
    acao: "",
    entidade: "",
    texto: "",
    data: ""
  });
  const [pagina, setPagina] = useState(0);
  const [temMais, setTemMais] = useState(false);
  const porPagina = 100;
  const [carregando, setCarregando] = useState(true);

  // Atualiza logs quando filtro de data ou página muda
  useEffect(() => {
    const fetchLogs = async () => {
      setCarregando(true);
      try {
        const params = {
          limit: porPagina,
          offset: pagina * porPagina,
        };
        if (filtros.data) params.data = filtros.data;
        const res = await axios.get("/api/logs", {
          headers: { Authorization: `Bearer ${user.token}` },
          params
        });
        setLogs(res.data);
        setTemMais(res.data.length === porPagina);
      } catch (err) {
        setLogs([]);
        setTemMais(false);
      } finally {
        setCarregando(false);
      }
    };
    fetchLogs();
  }, [user.token, filtros.data, pagina]);

  // Gerar listas únicas para filtros dropdown
  const usuarios = Array.from(new Set(logs.map(l => l.usuario_nome).filter(Boolean)));
  const entidades = Array.from(new Set(logs.map(l => l.entidade).filter(Boolean)));
  const acoes = Array.from(new Set(logs.map(l => l.acao).filter(Boolean)));

  // Filtro dinâmico (aplicado só nos 100 da página)
  const logsFiltrados = logs.filter((l) => {
    const { usuario, acao, entidade, texto } = filtros;
    return (
      (!usuario || l.usuario_nome === usuario) &&
      (!acao || l.acao === acao) &&
      (!entidade || l.entidade === entidade) &&
      (!texto ||
        (l.usuario_nome?.toLowerCase().includes(texto.toLowerCase()) ||
         l.detalhes?.toLowerCase?.().includes(texto.toLowerCase()) ||
         l.entidade?.toLowerCase().includes(texto.toLowerCase()) ||
         l.acao?.toLowerCase().includes(texto.toLowerCase()))
      )
    );
  });

  // Navegação
  function handleVoltar() {
    if (pagina > 0) setPagina(p => p - 1);
  }
  function handleAvancar() {
    if (temMais) setPagina(p => p + 1);
  }

  // Alinhar botões (flex)
  const Pagination = () => (
    <div className="flex justify-between items-center my-2">
      <button
        onClick={handleVoltar}
        className={`px-4 py-2 rounded ${pagina === 0 ? "bg-gray-200 text-gray-400 cursor-not-allowed" : "bg-[#D9E0FF] text-[#23263A] hover:bg-[#c6d3fc]"}`}
        disabled={pagina === 0}
      >
        ◀ Voltar
      </button>
      <span className="text-gray-600 text-sm">Página {pagina + 1}</span>
      <button
        onClick={handleAvancar}
        className={`px-4 py-2 rounded ${!temMais ? "bg-gray-200 text-gray-400 cursor-not-allowed" : "bg-[#D9E0FF] text-[#23263A] hover:bg-[#c6d3fc]"}`}
        disabled={!temMais}
      >
        Avançar ▶
      </button>
    </div>
  );

  return (
    <div className="max-w-6xl mx-auto mt-10 p-6 bg-white rounded-2xl shadow-2xl">
      <h2 className="text-2xl font-bold mb-4 text-[#23263A]">Auditoria do Sistema</h2>

      {/* FILTROS */}
      <div className="flex flex-wrap gap-4 mb-4 items-end">
        <div>
          <label className="block text-sm mb-1 font-medium">Data:</label>
          <input
            type="date"
            className="border rounded px-3 py-2"
            value={filtros.data}
            onChange={e => {
              setPagina(0);
              setFiltros(f => ({ ...f, data: e.target.value }));
            }}
            max={new Date().toISOString().slice(0, 10)}
          />
        </div>
        <div>
          <label className="block text-sm mb-1 font-medium">Usuário:</label>
          <select
            className="border rounded px-3 py-2"
            value={filtros.usuario}
            onChange={e => setFiltros(f => ({ ...f, usuario: e.target.value }))}
          >
            <option value="">Todos</option>
            {usuarios.map(u => <option key={u} value={u}>{u}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-sm mb-1 font-medium">Ação:</label>
          <select
            className="border rounded px-3 py-2"
            value={filtros.acao}
            onChange={e => setFiltros(f => ({ ...f, acao: e.target.value }))}
          >
            <option value="">Todas</option>
            {acoes.map(a => <option key={a} value={a}>{a.charAt(0).toUpperCase() + a.slice(1)}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-sm mb-1 font-medium">Entidade:</label>
          <select
            className="border rounded px-3 py-2"
            value={filtros.entidade}
            onChange={e => setFiltros(f => ({ ...f, entidade: e.target.value }))}
          >
            <option value="">Todas</option>
            {entidades.map(ent => <option key={ent} value={ent}>{ent.charAt(0).toUpperCase() + ent.slice(1)}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-sm mb-1 font-medium">Buscar:</label>
          <input
            type="text"
            placeholder="Buscar..."
            className="border rounded px-3 py-2 w-60"
            value={filtros.texto}
            onChange={e => setFiltros(f => ({ ...f, texto: e.target.value }))}
          />
        </div>
      </div>

      {/* Botões paginação em cima */}
      <Pagination />

      <div className="overflow-x-auto rounded-2xl border my-2">
        <table className="min-w-full text-sm">
          <thead className="bg-gray-100 text-gray-600 font-semibold">
            <tr>
              <th className="px-4 py-3 text-left">Data/Hora</th>
              <th className="px-4 py-3 text-left">Usuário</th>
              <th className="px-4 py-3 text-left">Ação</th>
              <th className="px-4 py-3 text-left">Entidade</th>
              <th className="px-4 py-3 text-left">ID</th>
              <th className="px-4 py-3 text-left">Detalhes</th>
            </tr>
          </thead>
          <tbody>
            {carregando ? (
              <tr>
                <td colSpan={6} className="text-center py-8 text-gray-400">Carregando...</td>
              </tr>
            ) : logsFiltrados.length === 0 ? (
              <tr>
                <td colSpan={6} className="text-center py-8 text-gray-400">Nenhum registro encontrado.</td>
              </tr>
            ) : (
              logsFiltrados.map((log) => (
                <tr key={log.id} className="border-t hover:bg-gray-50">
                  <td className="px-4 py-2 whitespace-nowrap">{new Date(log.criado_em).toLocaleString()}</td>
                  <td className="px-4 py-2">{log.usuario_nome}</td>
                  <td className="px-4 py-2 capitalize">{log.acao}</td>
                  <td className="px-4 py-2">{log.entidade}</td>
                  <td className="px-4 py-2">{log.entidade_id}</td>
                  <td className="px-4 py-2">{renderDetalhes(log)}</td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* Botões paginação embaixo */}
      <Pagination />
    </div>
  );
}
